```py
import cProfile

def create_list(lst_len: int):
    arr = []
    for i in range(0, lst_len):
        arr.append(i)

def print_statement(idx: int):
    if idx == 0:
        print("Starting array creation!")
    elif idx == 1:
        print("Array created successfully!")
    else:
        raise ValueError("Invalid index provided!")

def main():
    print_statement(0)
    create_list(400000)
    print_statement(1)

if __name__ == "__main__":
    cProfile.run("main()") 
```
